        max: Optional['types.EpisodeNodeMaxAggregateInput'] = None,
        having: Optional['types.EpisodeNodeScalarWhereWithAggregatesInput'] = None,
        count: Optional[Union[bool, 'types.EpisodeNodeCountAggregateInput']] = None,
